defmodule MyWebhookProxyController do
  use MyWebex.Web, :controller

  def fetch_content(conn, params) do
    url = params["target_url"]
    with {:ok, %HTTPoison.Response{status_code: 200, body: content}} <- HTTPoison.get(url),
         {:ok, _} <- validate_destination(url),
         {:ok, _} <- block_internal_ip_ranges(url),
