        |> put_status(500)
        |> render("error", %{reason: reason})
    end
  end

  defp validate_destination(url) do
    # Allowlist destinations (e.g., whitelisted URLs or domains)
    allowed_destinations = ["https://example.com"]
    Enum.any?(allowed_destinations, fn destination -> String.starts_with?(url, destination) end)
  end

  defp block_internal_ip_ranges(url) do
    # Block internal/private IP ranges (e.g., using a library like ipcalc)
    blocked_ips = ["192.168.0.0/16", "10.0.0.0/8"]
    Enum.any?(blocked_ips, fn ip_range -> IP.in_cidr?(url, ip_range) end)
  end

  defp control_redirects(content) do
    # Tightly control redirects (e.g., using a library like Plug.Redirect)
    case Plug.Redirect.parse_url(content) do
      {:ok, %{redirect: true}} ->
